body:
In Next.js 15 App Router, all components are Server Components by default. If you use `useState`, `useEffect`, or any other React hook, you must add the `'use client'` directive at the top of the file.

```tsx
// BAD — this will error because page.tsx is a Server Component
import { useState } from 'react';

export default function Page() {
  const [count, setCount] = useState(0); // Error!
  return <button onClick={() => setCount(count + 1)}>{count}</button>;
}

// GOOD — extract interactive parts to a Client Component
// components/counter.tsx
'use client';
import { useState } from 'react';

export function Counter() {
  const [count, setCount] = useState(0);
  return <button onClick={() => setCount(count + 1)}>{count}</button>;
}

// app/page.tsx — Server Component imports Client Component
import { Counter } from '@/components/counter';
export default function Page() {
  return <Counter />;
}
```

The fix is always to split: keep data fetching in the Server Component and move interactivity into a `'use client'` child component.

Props passed from Server Components to Client Components must be serializable. Functions, class instances, Dates (as objects), Maps, Sets, and Symbols cannot be passed directly.

```tsx
// BAD — passing a function from Server to Client Component
import { ClientChild } from './client-child';

export default function Page() {
  const handleClick = () => console.log('clicked');
  // Error: Functions cannot be passed directly to Client Components
  return <ClientChild onClick={handleClick} />;
}

// GOOD — define the handler inside the Client Component
// client-child.tsx
'use client';
export function ClientChild() {
  const handleClick = () => console.log('clicked');
  return <button onClick={handleClick}>Click</button>;
}
```

Serializable types include: strings, numbers, booleans, null, undefined, arrays, plain objects, Date (as ISO string), BigInt, and Server Action references (functions marked with `'use server'`). If you need to pass a Date, convert it to an ISO string first.

A Client Component cannot import and render a Server Component directly. However, you can pass a Server Component as `children` or any other JSX prop.

```tsx
// BAD — Client Component importing Server Component
'use client';
import { ServerData } from './server-data'; // This becomes a Client Component!

export function Wrapper() {
  return <div><ServerData /></div>;
}

// GOOD — pass Server Component as children from a parent Server Component
// app/page.tsx (Server Component)
import { ClientWrapper } from './client-wrapper';
import { ServerData } from './server-data';

export default function Page() {
  return (
    <ClientWrapper>
      <ServerData />
    </ClientWrapper>
  );
}

// client-wrapper.tsx
'use client';
export function ClientWrapper({ children }: { children: React.ReactNode }) {
  const [open, setOpen] = useState(true);
  return open ? <div>{children}</div> : null;
}
```

When a Server Component is imported inside a `'use client'` file, it gets treated as a Client Component and loses server-only capabilities.

In Next.js 15, `fetch()` requests in Server Components default to `cache: 'no-store'`, which is a breaking change from Next.js 14 where the default was `cache: 'force-cache'`.

```tsx
// Next.js 14 behavior: cached by default
// Next.js 15 behavior: NOT cached by default
const data = await fetch('https://api.example.com/data');

// To opt into caching in Next.js 15, explicitly set cache:
const data = await fetch('https://api.example.com/data', {
  cache: 'force-cache',
});

// Or use time-based revalidation:
const data = await fetch('https://api.example.com/data', {
  next: { revalidate: 3600 }, // revalidate every hour
});
```

This change was made because most fetch calls in practice need fresh data. If you are migrating from Next.js 14, audit all your `fetch()` calls and add explicit caching where needed to avoid performance regressions.

Server Actions defined with `'use server'` must always be async functions. A non-async function with the directive will cause a build error.

```tsx
// BAD — Server Action is not async
'use server';
export function createUser(formData: FormData) {
  // Error: Server actions must be async functions
  const name = formData.get('name');
}

// GOOD — Server Action is async
'use server';
export async function createUser(formData: FormData) {
  const name = formData.get('name') as string;
  await db.insert(users).values({ name });
}
```

This requirement exists because Server Actions are invoked via network requests from the client, and the framework needs to handle the asynchronous serialization/deserialization of arguments and return values.

You cannot put `'use server'` inside a `'use client'` file. Server Actions must be defined in a separate file or inline in a Server Component.

```tsx
// BAD — 'use server' inside a 'use client' file
'use client';

async function submitForm() {
  'use server'; // Error! Cannot use 'use server' in a Client Component
}

// GOOD — separate file for Server Actions
// app/actions.ts
'use server';
export async function submitForm(formData: FormData) {
  const title = formData.get('title') as string;
  await db.insert(posts).values({ title });
  revalidatePath('/posts');
}

// app/components/form.tsx
'use client';
import { submitForm } from '@/app/actions';

export function PostForm() {
  return (
    <form action={submitForm}>
      <input name="title" />
      <button type="submit">Create</button>
    </form>
  );
}
```

The `'use server'` directive marks the function as a server endpoint. Import the action into Client Components — React serializes the reference automatically.

The `useFormStatus` hook reads the status of the parent `<form>`. It must be called in a component that is rendered as a child of the form — not in the same component that renders the form.

```tsx
// BAD — useFormStatus in the same component as <form>
'use client';
import { useFormStatus } from 'react-dom';

export function MyForm() {
  const { pending } = useFormStatus(); // Always returns { pending: false }!
  return (
    <form action={someAction}>
      <button disabled={pending}>Submit</button>
    </form>
  );
}

// GOOD — useFormStatus in a child component
'use client';
import { useFormStatus } from 'react-dom';

function SubmitButton() {
  const { pending } = useFormStatus();
  return <button disabled={pending}>{pending ? 'Saving...' : 'Submit'}</button>;
}

export function MyForm() {
  return (
    <form action={someAction}>
      <input name="title" />
      <SubmitButton />
    </form>
  );
}
```

`useFormStatus` looks up the tree for the nearest `<form>` ancestor. If it is used in the component that renders the `<form>`, it finds no parent form and `pending` is always `false`.

React 19 renamed `useFormState` to `useActionState` and moved it from `react-dom` to `react`. The old API is deprecated.

```tsx
// BAD — deprecated API
import { useFormState } from 'react-dom';

// GOOD — React 19 API
'use client';
import { useActionState } from 'react';
import { createPost } from '@/app/actions';

export function PostForm() {
  const [state, formAction, isPending] = useActionState(createPost, {
    message: '',
    errors: {},
  });

  return (
    <form action={formAction}>
      <input name="title" />
      {state.errors?.title && <p>{state.errors.title}</p>}
      <button disabled={isPending}>{isPending ? 'Creating...' : 'Create'}</button>
      {state.message && <p>{state.message}</p>}
    </form>
  );
}
```

The third element in the returned tuple (`isPending`) is new in `useActionState` — it replaces the need for a separate `useFormStatus` call in many cases. The action function receives `(previousState, formData)` as arguments.

The `use()` API can be called conditionally (unlike other hooks), but it has its own constraints: it can only read Promises and React Context. It cannot be used with other types.

```tsx
// use() CAN be called conditionally — this is valid!
import { use } from 'react';

function UserProfile({ userPromise, showDetails }: {
  userPromise: Promise<User>;
  showDetails: boolean;
}) {
  if (showDetails) {
    const user = use(userPromise); // OK inside conditional!
    return <div>{user.name}</div>;
  }
  return <div>Hidden</div>;
}

// use() also works with Context
function ThemedButton() {
  const theme = use(ThemeContext); // Replaces useContext(ThemeContext)
  return <button style={{ color: theme.primary }}>Click</button>;
}
```

However, the Promise passed to `use()` must be created outside the component or memoized. Creating a new Promise each render causes an infinite loop. Typically, you create the Promise in a Server Component and pass it as a prop.

Using `cookies()`, `headers()`, or `searchParams` in a Server Component forces the entire route to be dynamically rendered. This means no static HTML is generated at build time.

```tsx
// This page will ALWAYS be dynamically rendered
import { cookies } from 'next/headers';

export default async function Page() {
  const cookieStore = await cookies();
  const theme = cookieStore.get('theme')?.value ?? 'light';
  return <div className={theme}>Content</div>;
}

// To keep the page static, move dynamic logic to a Client Component
// page.tsx (stays static)
import { ThemeSwitcher } from './theme-switcher';
export default function Page() {
  return <div><ThemeSwitcher />Content</div>;
}

// theme-switcher.tsx
'use client';
export function ThemeSwitcher() {
  // Read cookie on the client instead
  const theme = document.cookie.match(/theme=(\w+)/)?.[1] ?? 'light';
  return <div className={theme} />;
}
```

In Next.js 15, `cookies()` and `headers()` are now async and must be awaited. This is a breaking change from Next.js 14.

In Next.js 15, `cookies()` and `headers()` are asynchronous and must be awaited. This is a breaking change from Next.js 14 where they were synchronous.

```tsx
// Next.js 14 (synchronous)
import { cookies } from 'next/headers';
const cookieStore = cookies();
const token = cookieStore.get('token');

// Next.js 15 (async — must await)
import { cookies } from 'next/headers';
const cookieStore = await cookies();
const token = cookieStore.get('token');

// Same for headers
import { headers } from 'next/headers';
const headersList = await headers();
const userAgent = headersList.get('user-agent');
```

If you forget to await, you will get a TypeScript error or unexpected behavior at runtime. The Next.js codemod `npx @next/codemod@latest next-async-request-api .` can automatically update your codebase.

In Next.js 15, the `params` and `searchParams` props passed to page and layout components are now Promises and must be awaited.

```tsx
// Next.js 14
export default function Page({ params }: { params: { slug: string } }) {
  return <h1>{params.slug}</h1>;
}

// Next.js 15 — params is a Promise
export default async function Page({
  params,
}: {
  params: Promise<{ slug: string }>;
}) {
  const { slug } = await params;
  return <h1>{slug}</h1>;
}

// Same for searchParams
export default async function Page({
  searchParams,
}: {
  searchParams: Promise<{ q?: string }>;
}) {
  const { q } = await searchParams;
  return <div>Search: {q}</div>;
}
```

This applies to `page.tsx`, `layout.tsx`, `route.ts`, `generateMetadata`, and `generateStaticParams`. The codemod `npx @next/codemod@latest next-async-request-api .` handles this migration.

Next.js 15 changed the client-side router cache to no longer cache Page component segments by default. Every navigation now fetches fresh data from the server for page segments.

```tsx
// To restore the old caching behavior, configure next.config.ts:
import type { NextConfig } from 'next';

const nextConfig: NextConfig = {
  experimental: {
    staleTimes: {
      dynamic: 30,  // Cache dynamic pages for 30 seconds
      static: 180,  // Cache static pages for 180 seconds
    },
  },
};

export default nextConfig;
```

Layout segments are still cached and reused on navigation by default — only page segments changed. This is particularly important for apps that relied on the router cache to avoid refetching data on back/forward navigation. If you see more server requests after upgrading to Next.js 15, this is likely the cause.

Calling `revalidatePath()` or `revalidateTag()` in a Server Action does not immediately refetch data in the same request. The revalidation happens on the next request.

```tsx
'use server';
import { revalidatePath } from 'next/cache';

export async function createPost(formData: FormData) {
  const title = formData.get('title') as string;
  await db.insert(posts).values({ title });

  revalidatePath('/posts');
  // The /posts page will show fresh data on the NEXT request,
  // not in the response to this Server Action call.
  // However, Next.js automatically triggers a router refresh after
  // the action completes, so the user will see updated data.
}

// If you need the newly created data in the action's return value:
export async function createPost(prevState: State, formData: FormData) {
  const title = formData.get('title') as string;
  const [post] = await db.insert(posts).values({ title }).returning();
  revalidatePath('/posts');
  return { success: true, post }; // Return the data directly
}
```

Next.js handles the coordination — after a Server Action with `revalidatePath`, it refetches the affected segments and updates the UI.

`generateStaticParams` runs at build time to determine which paths to statically generate. It cannot access `cookies()`, `headers()`, or any request-scoped data.

```tsx
// BAD — cookies not available at build time
import { cookies } from 'next/headers';

export async function generateStaticParams() {
  const cookieStore = await cookies(); // Error at build!
  const token = cookieStore.get('token');
  const posts = await fetchPosts(token);
  return posts.map((p) => ({ slug: p.slug }));
}

// GOOD — use direct data fetching without request context
export async function generateStaticParams() {
  const posts = await db.query.posts.findMany({
    columns: { slug: true },
  });
  return posts.map((p) => ({ slug: p.slug }));
}
```

If your data fetching requires authentication, use a service-level API key or direct database access in `generateStaticParams`, not user-scoped cookies.

When using `generateMetadata`, the page component will not start rendering until the metadata function resolves. This means slow metadata fetches delay the entire page.

```tsx
// SLOW — sequential data fetching
export async function generateMetadata({ params }: Props): Promise<Metadata> {
  const { id } = await params;
  const product = await fetch(`/api/products/${id}`).then(r => r.json());
  return { title: product.name };
}

export default async function Page({ params }: Props) {
  const { id } = await params;
  const product = await fetch(`/api/products/${id}`).then(r => r.json());
  return <div>{product.name}</div>;
}

// BETTER — Next.js deduplicates fetch with the same URL
// Both generateMetadata and Page call the same URL,
// but only one actual fetch is made (React/Next.js memoizes it)
```

Next.js automatically deduplicates `fetch()` calls with the same URL and options within a single render pass. So calling the same fetch in both `generateMetadata` and your Page component results in only one actual network request.

Next.js middleware runs on the Edge Runtime, which does not support many Node.js APIs like `fs`, `path`, `crypto.randomBytes`, `Buffer`, or native modules.

```tsx
// middleware.ts — RUNS ON EDGE RUNTIME
import { NextResponse } from 'next/server';
import type { NextRequest } from 'next/server';

// BAD — Node.js APIs not available
import fs from 'fs'; // Error!
import { PrismaClient } from '@prisma/client'; // Error — uses native modules

// GOOD — use Web APIs and edge-compatible libraries
export function middleware(request: NextRequest) {
  const url = request.nextUrl.clone();
  const token = request.cookies.get('token')?.value;

  if (!token && url.pathname.startsWith('/dashboard')) {
    url.pathname = '/login';
    return NextResponse.redirect(url);
  }

  // Use Web Crypto API instead of Node crypto
  const array = new Uint8Array(16);
  crypto.getRandomValues(array);

  return NextResponse.next();
}
```

For JWT verification in middleware, use edge-compatible libraries like `jose` instead of `jsonwebtoken`. For database access, use HTTP-based clients (Prisma Accelerate, Neon serverless driver).

If a Server Component uses `await` or a Client Component uses `use()` to read a Promise, you need a `<Suspense>` boundary above it to show a loading state while the data loads. Without it, the entire page waits.

```tsx
// app/page.tsx
import { Suspense } from 'react';
import { SlowData } from './slow-data';

export default function Page() {
  return (
    <div>
      <h1>Dashboard</h1>
      {/* Without Suspense, the entire page waits for SlowData */}
      <Suspense fallback={<p>Loading data...</p>}>
        <SlowData />
      </Suspense>
    </div>
  );
}

// slow-data.tsx (Server Component)
async function SlowData() {
  const data = await fetch('https://slow-api.example.com/data', {
    cache: 'no-store',
  });
  const json = await data.json();
  return <pre>{JSON.stringify(json, null, 2)}</pre>;
}
```

Place `<Suspense>` boundaries strategically. Each boundary creates a streaming chunk — the shell renders instantly and data fills in as it resolves.

A `loading.tsx` file in a route segment automatically wraps the page in a `<Suspense>` boundary. This means you do not need to manually add `<Suspense>` around the page content.

```tsx
// app/dashboard/loading.tsx
export default function Loading() {
  return <div className="animate-pulse">Loading dashboard...</div>;
}

// app/dashboard/page.tsx — automatically wrapped in Suspense
export default async function Dashboard() {
  const data = await fetchDashboardData(); // loading.tsx shows while this resolves
  return <div>{data.summary}</div>;
}

// This is equivalent to:
// <Suspense fallback={<Loading />}>
//   <Dashboard />
// </Suspense>
```

However, `loading.tsx` only applies to the page segment, not to nested components. If you have multiple slow data fetches in child components, add explicit `<Suspense>` boundaries around each one for more granular streaming.

The `error.tsx` file in Next.js App Router must include the `'use client'` directive. It is a Client Component because it uses `useEffect` and needs to be interactive (offering a retry button).

```tsx
// app/dashboard/error.tsx
'use client'; // Required!

export default function Error({
  error,
  reset,
}: {
  error: Error & { digest?: string };
  reset: () => void;
}) {
  return (
    <div>
      <h2>Something went wrong!</h2>
      <p>{error.message}</p>
      <button onClick={() => reset()}>Try again</button>
    </div>
  );
}
```

Forgetting `'use client'` will cause the error boundary to not catch errors properly. Also note that `error.tsx` catches errors in its segment and below, but not errors in the `layout.tsx` of the same segment. To catch layout errors, place `error.tsx` in the parent segment or use `global-error.tsx`.

An `error.tsx` file catches errors thrown by `page.tsx` and child components in the same segment, but it does NOT catch errors from the `layout.tsx` in the same segment.

```
app/
  dashboard/
    layout.tsx    ← errors here are NOT caught by error.tsx below
    error.tsx     ← only catches errors from page.tsx and children
    page.tsx
```

```tsx
// To catch errors in dashboard/layout.tsx, you need:
// app/error.tsx (parent segment) or app/global-error.tsx

// app/global-error.tsx catches root layout errors
'use client';
export default function GlobalError({
  error,
  reset,
}: {
  error: Error & { digest?: string };
  reset: () => void;
}) {
  return (
    <html>
      <body>
        <h1>Something went wrong</h1>
        <button onClick={() => reset()}>Retry</button>
      </body>
    </html>
  );
}
```

`global-error.tsx` is the only way to catch errors in the root `layout.tsx`. It must define its own `<html>` and `<body>` tags since it replaces the root layout when active.

In React 19, function components can accept `ref` as a regular prop. The `forwardRef` wrapper is no longer required.

```tsx
// React 18 — needed forwardRef
import { forwardRef } from 'react';

const Input = forwardRef<HTMLInputElement, InputProps>((props, ref) => {
  return <input ref={ref} {...props} />;
});

// React 19 — ref is just a prop
function Input({ ref, ...props }: InputProps & { ref?: React.Ref<HTMLInputElement> }) {
  return <input ref={ref} {...props} />;
}

// Usage is the same
function Form() {
  const inputRef = useRef<HTMLInputElement>(null);
  return <Input ref={inputRef} placeholder="Type here" />;
}
```

`forwardRef` still works but is deprecated and will be removed in a future version. The React team provides a codemod: `npx types-react-codemod@latest preset-19 .` to update your types. Existing `forwardRef` components continue to work during the migration.

When using parallel routes (named slots like `@modal`), you must provide a `default.tsx` for each slot. Without it, a hard refresh (full page reload) will result in a 404.

```
app/
  layout.tsx
  page.tsx
  @modal/
    default.tsx    ← REQUIRED for hard refresh to work
    (.)photo/
      [id]/
        page.tsx
```

```tsx
// app/@modal/default.tsx
export default function Default() {
  return null; // Return null when no modal is active
}

// app/layout.tsx
export default function Layout({
  children,
  modal,
}: {
  children: React.ReactNode;
  modal: React.ReactNode;
}) {
  return (
    <div>
      {children}
      {modal}
    </div>
  );
}
```

On soft navigation (client-side), Next.js remembers the slot state. On hard navigation, it cannot reconstruct the slot state so it renders `default.tsx`. If no `default.tsx` exists, Next.js renders a 404.

Intercepting route conventions `(.)`, `(..)`, `(...)` match based on route segments, not the filesystem directory structure. This is a common source of confusion.

```
// Filesystem structure:
app/
  feed/
    page.tsx
    @modal/
      (..)photo/       ← This does NOT go up one filesystem dir
        [id]/
          page.tsx
  photo/
    [id]/
      page.tsx

// Route segments:
// /feed          → app/feed/page.tsx
// /photo/[id]    → app/photo/[id]/page.tsx
// (..) in @modal means "one route segment up" = from /feed to /
// So (..)photo matches /photo/[id]
```

```tsx
// app/feed/@modal/(..)photo/[id]/page.tsx
// This intercepts /photo/123 when navigated from /feed
export default async function PhotoModal({
  params,
}: {
  params: Promise<{ id: string }>;
}) {
  const { id } = await params;
  return <Modal><Photo id={id} /></Modal>;
}
```

Because `@modal` is a named slot (not a route segment), `(..)` goes up from `/feed` to `/`, then matches `photo/[id]`.

The Next.js `<Image>` component requires either explicit `width` and `height` props or the `fill` prop. Omitting both causes a build error.

```tsx
import Image from 'next/image';

// BAD — missing dimensions
<Image src="/hero.jpg" alt="Hero" />

// GOOD — explicit dimensions
<Image src="/hero.jpg" alt="Hero" width={800} height={400} />

// GOOD — fill mode (parent must have position: relative)
<div style={{ position: 'relative', width: '100%', height: '400px' }}>
  <Image
    src="/hero.jpg"
    alt="Hero"
    fill
    style={{ objectFit: 'cover' }}
    sizes="100vw"
  />
</div>

// For remote images, configure domains in next.config.ts:
const nextConfig: NextConfig = {
  images: {
    remotePatterns: [
      { protocol: 'https', hostname: 'cdn.example.com' },
    ],
  },
};
```

When using `fill`, always provide the `sizes` prop to help the browser pick the right image size. Without `sizes`, the browser defaults to `100vw` which may download unnecessarily large images.

When using `next/font/google`, you must specify the `subsets` option. Omitting it causes a build warning or error and may load all font subsets, bloating the page.

```tsx
// BAD — no subsets
import { Inter } from 'next/font/google';
const inter = Inter({}); // Warning: Missing subsets

// GOOD — specify subsets
import { Inter } from 'next/font/google';
const inter = Inter({
  subsets: ['latin'],
  display: 'swap',
});

// Variable fonts with specific weights
import { Roboto } from 'next/font/google';
const roboto = Roboto({
  weight: ['400', '700'],
  subsets: ['latin'],
  display: 'swap',
});

// Usage in layout
export default function RootLayout({ children }: { children: React.ReactNode }) {
  return (
    <html lang="en" className={inter.className}>
      <body>{children}</body>
    </html>
  );
}
```

Fonts declared at the module level are automatically self-hosted and deduplicated. Do not declare fonts inside components — declare them in the layout file or a shared module.

In Next.js 15, a GET Route Handler is statically evaluated at build time if it does not use dynamic functions (`cookies()`, `headers()`, `searchParams`) or the `dynamic = 'force-dynamic'` export.

```tsx
// app/api/data/route.ts
// This GET handler is STATIC — built once, returns same response
export async function GET() {
  const data = await db.query.posts.findMany();
  return Response.json(data);
}

// To make it dynamic, use one of:

// Option 1: Export dynamic config
export const dynamic = 'force-dynamic';
export async function GET() {
  const data = await db.query.posts.findMany();
  return Response.json(data);
}

// Option 2: Use a dynamic function
import { cookies } from 'next/headers';
export async function GET() {
  const cookieStore = await cookies(); // Forces dynamic
  const data = await db.query.posts.findMany();
  return Response.json(data);
}

// Option 3: Use revalidation
export const revalidate = 60; // ISR — revalidate every 60 seconds
export async function GET() {
  const data = await db.query.posts.findMany();
  return Response.json(data);
}
```

POST, PUT, PATCH, and DELETE handlers are always dynamic.

Server Actions can return values, but the return value must be serializable (same constraints as passing props from Server to Client Components).

```tsx
// BAD — returning non-serializable data
'use server';
export async function getUser() {
  const user = await db.query.users.findFirst();
  return {
    ...user,
    createdAt: user.createdAt, // Date object — not serializable!
    validate: () => true, // Function — not serializable!
  };
}

// GOOD — serialize everything
'use server';
export async function getUser() {
  const user = await db.query.users.findFirst();
  return {
    ...user,
    createdAt: user.createdAt.toISOString(), // String — OK
    // Omit functions entirely
  };
}
```

This applies to the return value used with `useActionState` as well. If your action state includes dates, always convert them to strings or timestamps before returning.

Next.js 15 supports TypeScript configuration files natively. You can use `next.config.ts` with full type checking.

```tsx
// next.config.ts
import type { NextConfig } from 'next';

const nextConfig: NextConfig = {
  images: {
    remotePatterns: [
      { protocol: 'https', hostname: 'cdn.example.com' },
    ],
  },
  experimental: {
    ppr: true, // Partial Prerendering
    typedRoutes: true,
  },
};

export default nextConfig;
```

If both `next.config.ts` and `next.config.js` exist, the `.ts` file takes precedence. When migrating, rename the file and add the `NextConfig` type annotation for autocompletion.

Incremental Static Regeneration in the App Router does not use `getStaticProps`. Instead, you export a `revalidate` constant from the page or use `fetch` options.

```tsx
// app/products/page.tsx

// Option 1: Route segment config
export const revalidate = 3600; // Revalidate every hour

export default async function ProductsPage() {
  const products = await db.query.products.findMany();
  return <ProductList products={products} />;
}

// Option 2: Per-fetch revalidation
export default async function ProductsPage() {
  const res = await fetch('https://api.example.com/products', {
    next: { revalidate: 3600 },
  });
  const products = await res.json();
  return <ProductList products={products} />;
}

// On-demand revalidation via Server Action:
'use server';
import { revalidatePath, revalidateTag } from 'next/cache';

export async function refreshProducts() {
  revalidateTag('products');
  // or: revalidatePath('/products');
}
```

The lowest `revalidate` value in a route wins. If a layout has `revalidate = 3600` and a page has `revalidate = 60`, the page revalidates every 60 seconds.

The `redirect()` function from `next/navigation` works by throwing a special error. If you catch it in a try/catch, the redirect will not work.

```tsx
// BAD — redirect caught by try/catch
import { redirect } from 'next/navigation';

export async function createPost(formData: FormData) {
  'use server';
  try {
    await db.insert(posts).values({ title: formData.get('title') as string });
    redirect('/posts'); // Caught by catch block!
  } catch (error) {
    return { error: 'Failed to create post' };
  }
}

// GOOD — redirect outside try/catch
export async function createPost(formData: FormData) {
  'use server';
  let success = false;
  try {
    await db.insert(posts).values({ title: formData.get('title') as string });
    success = true;
  } catch (error) {
    return { error: 'Failed to create post' };
  }
  if (success) {
    redirect('/posts');
  }
}
```

The same applies to `notFound()` — it also throws internally. Always place these calls outside of try/catch blocks.

The `redirect()` function from `next/navigation` only works in Server Components, Server Actions, and Route Handlers. In Client Components, use `useRouter().push()`.

```tsx
// BAD — redirect in Client Component
'use client';
import { redirect } from 'next/navigation';

export function LoginButton() {
  function handleClick() {
    redirect('/dashboard'); // This won't work!
  }
  return <button onClick={handleClick}>Login</button>;
}

// GOOD — useRouter in Client Component
'use client';
import { useRouter } from 'next/navigation';

export function LoginButton() {
  const router = useRouter();
  function handleClick() {
    router.push('/dashboard');
  }
  return <button onClick={handleClick}>Login</button>;
}
```

Use `redirect()` in server-side code (Server Components, Server Actions, Route Handlers) and `useRouter` in Client Components. For conditional redirects in middleware, use `NextResponse.redirect()`.

Using `next/dynamic` in a Server Component converts it to a Client Component implicitly. If you want code splitting in Server Components, use regular `import()` with `<Suspense>`.

```tsx
// BAD — next/dynamic in Server Component makes it a Client Component
import dynamic from 'next/dynamic';
const HeavyChart = dynamic(() => import('./heavy-chart'));

export default function Page() {
  return <HeavyChart />; // Now a client-rendered component
}

// GOOD for Server Components — use React.lazy + Suspense or just import
import { Suspense } from 'react';
import { HeavyChart } from './heavy-chart'; // Server Component

export default function Page() {
  return (
    <Suspense fallback={<p>Loading chart...</p>}>
      <HeavyChart />
    </Suspense>
  );
}

// next/dynamic IS correct for Client Components that need lazy loading:
'use client';
import dynamic from 'next/dynamic';
const Editor = dynamic(() => import('./editor'), { ssr: false });
```

Use `next/dynamic` with `{ ssr: false }` specifically when a Client Component needs a browser-only library (e.g., a WYSIWYG editor).

In Next.js 15, metadata from `layout.tsx` and `page.tsx` in the same segment is not deeply merged. The page metadata replaces matching fields from the layout.

```tsx
// app/layout.tsx
export const metadata: Metadata = {
  title: { default: 'My App', template: '%s | My App' },
  description: 'My application description',
  openGraph: {
    siteName: 'My App',
    type: 'website',
  },
};

// app/about/page.tsx
export const metadata: Metadata = {
  title: 'About', // Becomes 'About | My App' via template
  // description is inherited from layout
  // But if you set openGraph here, it REPLACES the layout's openGraph entirely
  openGraph: {
    title: 'About Us', // siteName and type from layout are LOST
  },
};

// To preserve parent openGraph fields, re-specify them:
export const metadata: Metadata = {
  title: 'About',
  openGraph: {
    title: 'About Us',
    siteName: 'My App', // Must repeat
    type: 'website', // Must repeat
  },
};
```

The `title.template` pattern is the recommended way to build consistent titles. Shallow fields like `description` are inherited, but nested objects like `openGraph` are fully replaced.

The optimistic state from `useOptimistic` is automatically replaced when the parent Server Component re-renders and passes updated props. This is by design but can surprise developers.

```tsx
'use client';
import { useOptimistic } from 'react';

export function LikeButton({ likes }: { likes: number }) {
  const [optimisticLikes, addOptimisticLike] = useOptimistic(
    likes,
    (current, _: null) => current + 1
  );

  async function handleLike() {
    addOptimisticLike(null);
    await likePost(); // Server Action
    // After this completes, the Server Component re-renders
    // and passes the new `likes` count, replacing optimistic state
  }

  return (
    <button onClick={handleLike}>
      {optimisticLikes} likes
    </button>
  );
}
```

If the action fails, the optimistic state reverts to the last prop value. Make sure your Server Action calls `revalidatePath` or `revalidateTag` so the parent re-renders with correct data after success.

If a component inside a `<Suspense>` boundary throws an unrecoverable error during streaming SSR, the entire stream can fail. Use error boundaries alongside Suspense for resilient streaming.

```tsx
// Resilient streaming pattern:
import { Suspense } from 'react';

// error.tsx handles thrown errors, loading.tsx handles Suspense
// But for fine-grained control, nest error boundaries:

export default function Page() {
  return (
    <div>
      <h1>Dashboard</h1>
      <ErrorBoundary fallback={<p>Failed to load stats</p>}>
        <Suspense fallback={<p>Loading stats...</p>}>
          <Stats />
        </Suspense>
      </ErrorBoundary>
      <ErrorBoundary fallback={<p>Failed to load chart</p>}>
        <Suspense fallback={<p>Loading chart...</p>}>
          <Chart />
        </Suspense>
      </ErrorBoundary>
    </div>
  );
}
```

In Next.js App Router, `error.tsx` serves as the error boundary for the segment. For more granular error handling within a page, use a custom `ErrorBoundary` class component wrapping each `<Suspense>`.

Server Actions use a POST request under the hood with a default body size limit of 1MB. Sending large payloads (e.g., base64-encoded files) will fail silently or throw a confusing error.

```tsx
// next.config.ts — increase the limit
import type { NextConfig } from 'next';

const nextConfig: NextConfig = {
  experimental: {
    serverActions: {
      bodySizeLimit: '10mb',
    },
  },
};

export default nextConfig;

// Better approach: use a Route Handler for file uploads
// app/api/upload/route.ts
export async function POST(request: Request) {
  const formData = await request.formData();
  const file = formData.get('file') as File;
  const bytes = await file.arrayBuffer();
  // Process the file...
  return Response.json({ success: true });
}
```

For file uploads, prefer Route Handlers over Server Actions. Route Handlers give you more control over streaming and progress tracking.

Next.js 15 introduces the `'use cache'` directive as the replacement for `unstable_cache`. The `'use cache'` directive can be applied to functions or entire files.

```tsx
// OLD approach with unstable_cache
import { unstable_cache } from 'next/cache';

const getCachedPosts = unstable_cache(
  async () => {
    return db.query.posts.findMany();
  },
  ['posts'],
  { revalidate: 3600 }
);

// NEW approach with 'use cache' (Next.js 15 canary)
async function getPosts() {
  'use cache';
  return db.query.posts.findMany();
}

// With cache lifetime configuration
import { cacheLife } from 'next/cache';

async function getPosts() {
  'use cache';
  cacheLife('hours');
  return db.query.posts.findMany();
}
```

Note: `'use cache'` is still experimental in Next.js 15 and requires `experimental.dynamicIO` in `next.config.ts`. For stable code, continue using `unstable_cache` or fetch-level caching.

The `not-found.tsx` file does not automatically render for missing dynamic routes. You must explicitly call `notFound()` from `next/navigation`.

```tsx
// app/posts/[slug]/page.tsx
import { notFound } from 'next/navigation';

export default async function PostPage({
  params,
}: {
  params: Promise<{ slug: string }>;
}) {
  const { slug } = await params;
  const post = await db.query.posts.findFirst({
    where: eq(posts.slug, slug),
  });

  if (!post) {
    notFound(); // Triggers not-found.tsx
  }

  return <article>{post.title}</article>;
}

// app/posts/[slug]/not-found.tsx
export default function NotFound() {
  return <div>Post not found</div>;
}
```

The `app/not-found.tsx` at the root handles unmatched routes globally. Segment-level `not-found.tsx` files handle `notFound()` calls within that segment. If no segment-level `not-found.tsx` exists, it bubbles up to the nearest parent.

This error occurs when you try to use React hooks like `useState`, `useEffect`, or `useRef` in a Server Component (any component without the `'use client'` directive in App Router).

```
Error: useState is not a function
// or
Error: (0 , react__WEBPACK_IMPORTED_MODULE_0__.useState) is not a function
```

```tsx
// FIX: Add 'use client' directive at the top of the file
'use client';
import { useState } from 'react';

export function Counter() {
  const [count, setCount] = useState(0);
  return <button onClick={() => setCount(c => c + 1)}>{count}</button>;
}
```

Alternatively, restructure your component to keep data fetching in the Server Component and pass data as props to a Client Component child.

This error appears when you pass non-serializable values (functions, class instances, Dates, Maps, Sets) from a Server Component to a Client Component.

```
Error: Only plain objects, and a few built-ins, can be passed to Client Components from Server Components. Classes or null prototypes are not supported.
```

```tsx
// BAD — passing a Date object
export default async function Page() {
  const user = await getUser();
  return <ClientProfile user={user} />; // user.createdAt is a Date!
}

// FIX — serialize dates before passing
export default async function Page() {
  const user = await getUser();
  return (
    <ClientProfile
      user={{
        ...user,
        createdAt: user.createdAt.toISOString(),
      }}
    />
  );
}
```

Common culprits: Prisma/Drizzle models with Date fields, Mongoose documents, or any object with a non-plain prototype. Serialize everything to plain objects, strings, and numbers before passing to Client Components.

This error occurs when `headers()`, `cookies()`, or other request-scoped functions are called outside of a request context (e.g., at module scope, in `generateStaticParams`, or during build time).

```
Error: Invariant: headers() expects to have requestAsyncStorage, none available.
```

```tsx
// BAD — calling headers at module scope
import { headers } from 'next/headers';
const headersList = await headers(); // Error — no request context!

// GOOD — call inside a Server Component or Route Handler
import { headers } from 'next/headers';

export default async function Page() {
  const headersList = await headers(); // OK — inside request context
  const auth = headersList.get('authorization');
  return <div>Auth: {auth}</div>;
}

// GOOD — in a Route Handler
export async function GET() {
  const headersList = await headers();
  return Response.json({ ua: headersList.get('user-agent') });
}
```

Request-scoped functions can only be called during the execution of a request. They cannot be used in `generateStaticParams`, top-level module code, or `next.config.ts`.

When `redirect()` from `next/navigation` is called inside a try/catch, the catch block intercepts the redirect error, preventing navigation.

```
Error: NEXT_REDIRECT
// or the redirect simply doesn't work
```

```tsx
// BAD
import { redirect } from 'next/navigation';

export async function submitAction(formData: FormData) {
  'use server';
  try {
    await saveData(formData);
    redirect('/success'); // Caught by catch!
  } catch (e) {
    return { error: 'Something went wrong' };
  }
}

// FIX — redirect outside try/catch
export async function submitAction(formData: FormData) {
  'use server';
  let result;
  try {
    result = await saveData(formData);
  } catch (e) {
    return { error: 'Something went wrong' };
  }
  redirect('/success');
}
```

Both `redirect()` and `notFound()` throw special errors internally. Always call them after the try/catch block. You can also check `isRedirectError(e)` from `next/dist/client/components/redirect` to re-throw redirect errors.

This error occurs when a Server Component tries to pass an event handler (function) as a prop to a Client Component.

```
Error: Event handlers cannot be passed to Client Component props.
<button onClick={function} children=...>
                ^^^^^^^^^^ If you need interactivity, consider converting part of this to a Client Component.
```

```tsx
// BAD — Server Component passing onClick
export default function Page() {
  return <button onClick={() => console.log('click')}>Click</button>;
}

// FIX — extract to Client Component
// components/click-button.tsx
'use client';
export function ClickButton() {
  return <button onClick={() => console.log('click')}>Click</button>;
}

// page.tsx
import { ClickButton } from '@/components/click-button';
export default function Page() {
  return <ClickButton />;
}
```

All event handlers (`onClick`, `onChange`, `onSubmit`, etc.) require client-side JavaScript. Move them into `'use client'` components.

This error means you are importing a module marked with `server-only` in a Client Component, or you haven't installed the `server-only` package.

```
Error: Cannot find module 'server-only'
```

```bash
# Install the package
npm install server-only
```

```tsx
// lib/db.ts — mark as server-only to prevent client imports
import 'server-only';
import { drizzle } from 'drizzle-orm/neon-http';

export const db = drizzle(process.env.DATABASE_URL!);

// If a Client Component imports this file:
// 'use client';
// import { db } from '@/lib/db'; // Build error! Good — prevents leaking secrets
```

Use `import 'server-only'` in any module that contains secrets, direct database access, or server-only logic. This gives a clear build-time error instead of a confusing runtime error. There is also a `client-only` package for the reverse case.

This error usually means you have a default export that is `undefined` — often caused by exporting a named function but forgetting the `default` keyword in a page or layout file.

```
Error: Unsupported Server Component type: undefined
```

```tsx
// BAD — missing default export
export function Page() {
  return <div>Hello</div>;
}
// Next.js expects: export default function Page()

// BAD — exporting undefined
const Page = undefined;
export default Page;

// FIX
export default function Page() {
  return <div>Hello</div>;
}
```

This also happens when a barrel file re-exports something that doesn't exist, or when a circular import causes a module to resolve as `undefined`. Check your import chain if the fix above doesn't resolve it.

React Context (`createContext`, `useContext`) cannot be used in Server Components because they require client-side state.

```
Error: createContext is not supported in Server Components
```

```tsx
// BAD — createContext in Server Component
import { createContext } from 'react';
export const ThemeContext = createContext('light'); // Error in Server Component!

// FIX — create context in a Client Component file
// lib/theme-context.tsx
'use client';
import { createContext, useContext } from 'react';

export const ThemeContext = createContext<string>('light');

export function ThemeProvider({ children, theme }: {
  children: React.ReactNode;
  theme: string;
}) {
  return (
    <ThemeContext.Provider value={theme}>
      {children}
    </ThemeContext.Provider>
  );
}

export function useTheme() {
  return useContext(ThemeContext);
}

// app/layout.tsx — Server Component wrapping Client Provider
import { ThemeProvider } from '@/lib/theme-context';
export default function Layout({ children }: { children: React.ReactNode }) {
  return <ThemeProvider theme="dark">{children}</ThemeProvider>;
}
```

In Client Components, you cannot render a Promise directly. This error often occurs when trying to use async/await patterns that only work in Server Components.

```
Error: Objects are not valid as a React child (found: [object Promise]).
If you meant to render a collection of children, use an array instead.
```

```tsx
// BAD — async Client Component
'use client';
export default async function Profile() {
  const user = await fetchUser(); // Client Components can't be async!
  return <div>{user.name}</div>;
}

// FIX Option 1 — use useEffect + useState
'use client';
import { useState, useEffect } from 'react';

export default function Profile() {
  const [user, setUser] = useState<User | null>(null);
  useEffect(() => {
    fetchUser().then(setUser);
  }, []);
  if (!user) return <p>Loading...</p>;
  return <div>{user.name}</div>;
}

// FIX Option 2 — use React 19 use() hook
'use client';
import { use } from 'react';

export default function Profile({ userPromise }: { userPromise: Promise<User> }) {
  const user = use(userPromise);
  return <div>{user.name}</div>;
}
```

Async components are only supported as Server Components. In Client Components, use `useEffect`, React Query, SWR, or the `use()` hook with a Promise passed from a Server Component.

This Next.js error occurs when a third-party library uses `useEffect` internally but you import it in a Server Component file.

```
Error: You're importing a component that needs useEffect. It only works in a Client Component but none of its parents are marked with "use client".
```

```tsx
// BAD — importing a client-only library in a Server Component
import { Toaster } from 'react-hot-toast'; // Uses useEffect internally

export default function Layout({ children }: { children: React.ReactNode }) {
  return (
    <html>
      <body>
        {children}
        <Toaster /> {/* Error! */}
      </body>
    </html>
  );
}

// FIX — wrap in a Client Component
// components/toaster-provider.tsx
'use client';
import { Toaster } from 'react-hot-toast';
export function ToasterProvider() {
  return <Toaster />;
}

// app/layout.tsx
import { ToasterProvider } from '@/components/toaster-provider';
export default function Layout({ children }: { children: React.ReactNode }) {
  return (
    <html>
      <body>
        {children}
        <ToasterProvider />
      </body>
    </html>
  );
}
```

This pattern is common with toast libraries, animation libraries (Framer Motion), and UI component libraries. Create a thin `'use client'` wrapper component.

Hydration errors occur when the server-rendered HTML differs from what the client renders. Common causes: using `Date.now()`, `Math.random()`, `window`, or `localStorage` during render.

```
Error: Hydration failed because the server rendered HTML didn't match the client.
Text content does not match. Server: "March 28" Client: "March 27"
```

```tsx
// BAD — Date differs between server and client
export default function Page() {
  return <p>{new Date().toLocaleDateString()}</p>;
}

// FIX — use useEffect for client-only values
'use client';
import { useState, useEffect } from 'react';

export function LocalDate() {
  const [date, setDate] = useState<string>('');
  useEffect(() => {
    setDate(new Date().toLocaleDateString());
  }, []);
  return <p>{date}</p>;
}

// FIX — or suppress hydration warning for intentional mismatches
export function LocalDate() {
  return <p suppressHydrationWarning>{new Date().toLocaleDateString()}</p>;
}
```

Other common causes: browser extensions modifying the DOM, conditional rendering based on `typeof window !== 'undefined'`, and CSS-in-JS libraries not configured for SSR.

This Next.js build error occurs when a page uses dynamic functions (`cookies()`, `headers()`, `searchParams`) but is expected to be static.

```
Error: Dynamic server usage: Page couldn't be rendered statically because it used `cookies`.
```

```tsx
// If you WANT the page to be dynamic:
export const dynamic = 'force-dynamic';

// Or if you want static generation with revalidation:
export const revalidate = 3600;

// Or move the dynamic code to a Suspense boundary:
import { Suspense } from 'react';

export default function Page() {
  return (
    <div>
      <h1>Static content</h1>
      <Suspense fallback={<p>Loading...</p>}>
        <DynamicPart />
      </Suspense>
    </div>
  );
}

async function DynamicPart() {
  const cookieStore = await cookies();
  return <p>Theme: {cookieStore.get('theme')?.value}</p>;
}
```

With PPR enabled, the Suspense approach gives you the best of both worlds: static shell + streamed dynamic content.

This error occurs when you try to access a named export from a `'use client'` module using dot notation in a Server Component.

```
Error: You cannot dot into a client module from a server component.
```

```tsx
// BAD — dot access into client module
// ui.tsx
'use client';
export const Button = () => <button>Click</button>;
export const Input = () => <input />;

// page.tsx (Server Component)
import * as UI from './ui';
UI.Button; // Error!

// FIX — use named imports
import { Button, Input } from './ui'; // OK

export default function Page() {
  return <Button />;
}
```

Always use named imports (`import { X }`) or default imports (`import X`) when importing from `'use client'` files into Server Components. Namespace imports (`import * as X`) are not supported across the server/client boundary.

This error appears when you pass a regular function (not a Server Action) from a Server Component to a Client Component.

```
Error: Functions cannot be passed directly to Client Components unless you explicitly expose it by marking it with "use server".
```

```tsx
// BAD — regular function passed to Client Component
export default function Page() {
  function handleSubmit(data: string) {
    console.log(data);
  }
  return <ClientForm onSubmit={handleSubmit} />;
}

// FIX — mark as Server Action
export default function Page() {
  async function handleSubmit(data: string) {
    'use server';
    console.log(data);
  }
  return <ClientForm onSubmit={handleSubmit} />;
}

// Or define in a separate file
// actions.ts
'use server';
export async function handleSubmit(data: string) {
  console.log(data);
}
```

Only `'use server'` functions (Server Actions) can cross the server-to-client boundary. They are serialized as references that trigger server-side execution when called.

When using PPR or streaming, dynamic functions inside a Suspense boundary require a fallback. Without a fallback, Next.js cannot determine the static/dynamic split.

```
Error: Route "/dashboard" used `cookies` inside a "use cache" or during prerendering without a Suspense boundary with a fallback UI.
```

```tsx
// BAD — no fallback
import { Suspense } from 'react';
import { cookies } from 'next/headers';

export default function Page() {
  return (
    <Suspense> {/* Missing fallback prop */}
      <UserInfo />
    </Suspense>
  );
}

// FIX — add a fallback
export default function Page() {
  return (
    <Suspense fallback={<div>Loading user...</div>}>
      <UserInfo />
    </Suspense>
  );
}

async function UserInfo() {
  const cookieStore = await cookies();
  const name = cookieStore.get('name')?.value;
  return <p>Hello {name}</p>;
}
```

Always provide a meaningful `fallback` prop on `<Suspense>` boundaries that wrap dynamic content. The fallback is shown during the static prerender and then replaced when the dynamic content streams in.

Client Components cannot be `async` functions. This error appears when you add `async` to a component in a `'use client'` file.

```
Error: async/await is not yet supported in Client Components, only Server Components.
```

```tsx
// BAD
'use client';
export default async function Dashboard() {
  const data = await fetchData(); // Error!
  return <div>{data.title}</div>;
}

// FIX Option 1 — fetch in Server Component, pass as props
// page.tsx (Server Component)
import { Dashboard } from './dashboard';
export default async function Page() {
  const data = await fetchData();
  return <Dashboard data={data} />;
}

// FIX Option 2 — use React 19 use() hook
'use client';
import { use } from 'react';

export function Dashboard({ dataPromise }: { dataPromise: Promise<Data> }) {
  const data = use(dataPromise); // Suspends until resolved
  return <div>{data.title}</div>;
}

// FIX Option 3 — useEffect for client-only fetching
'use client';
import { useState, useEffect } from 'react';
export function Dashboard() {
  const [data, setData] = useState<Data | null>(null);
  useEffect(() => { fetchData().then(setData); }, []);
  return data ? <div>{data.title}</div> : <p>Loading...</p>;
}
```

This error occurs when a page file has `'use client'` but Next.js tries to render it as a Server Component (e.g., during static generation).

```
Error: Attempted to call the default export of "/app/page.tsx" from the server but it's on the client.
```

```tsx
// BAD — page.tsx should not be 'use client' if it uses server features
'use client';
export default function Page() {
  return <div>Hello</div>;
}

// While this works for simple pages, it prevents:
// - Server-side data fetching
// - Metadata export
// - Static generation

// BETTER — keep page.tsx as Server Component, extract client parts
// app/page.tsx
import { ClientContent } from './client-content';
export const metadata = { title: 'Home' }; // Only works in Server Components

export default function Page() {
  return <ClientContent />;
}
```

Pages should generally be Server Components. Extract interactive parts into Client Component children. This allows metadata exports and server-side data fetching to work correctly.

Next.js `<Image>` requires consistent dimension handling. If you override one dimension via CSS, the other may distort.

```
Error: Image with src "/hero.jpg" has either width or height modified, but not the other.
If you use CSS to change the size of your image, also include the styles 'width: auto' or 'height: auto'.
```

```tsx
// BAD — only width set in CSS
<Image src="/hero.jpg" alt="" width={800} height={400}
  style={{ width: '100%' }} // height is not adjusted
/>

// FIX — add height: auto
<Image src="/hero.jpg" alt="" width={800} height={400}
  style={{ width: '100%', height: 'auto' }}
/>

// Or use fill mode instead
<div style={{ position: 'relative', width: '100%', aspectRatio: '2/1' }}>
  <Image src="/hero.jpg" alt="" fill style={{ objectFit: 'cover' }} sizes="100vw" />
</div>
```

The `width` and `height` props set the intrinsic dimensions for layout shift prevention. If you override one in CSS, add `auto` for the other to maintain aspect ratio.

Next.js middleware cannot return a response body. It can only rewrite, redirect, or modify headers.

```
Error: Middleware is returning a response body, which is not supported.
```

```tsx
// BAD — returning JSON from middleware
import { NextResponse } from 'next/server';

export function middleware() {
  return NextResponse.json({ error: 'Unauthorized' }, { status: 401 });
}

// FIX — redirect or rewrite instead
export function middleware(request: NextRequest) {
  const token = request.cookies.get('token');
  if (!token) {
    // Option 1: Redirect
    return NextResponse.redirect(new URL('/login', request.url));
    // Option 2: Rewrite to an error page
    return NextResponse.rewrite(new URL('/unauthorized', request.url));
  }
  return NextResponse.next();
}

// If you need to return JSON, use a Route Handler instead:
// app/api/auth/check/route.ts
export async function GET(request: Request) {
  return Response.json({ error: 'Unauthorized' }, { status: 401 });
}
```

Middleware is designed for routing decisions, not for serving responses. Use Route Handlers for API endpoints.

This React 19 error occurs when a component suspends during a synchronous user interaction (like typing) without a proper transition.

```
Error: A component suspended while responding to synchronous input. This will cause the UI to be replaced with a loading indicator.
```

```tsx
// BAD — suspending on every keystroke
'use client';
import { use, useState } from 'react';

function SearchResults({ query }: { query: string }) {
  const results = use(fetchResults(query)); // Suspends on every keystroke!
  return <ul>{results.map(r => <li key={r.id}>{r.title}</li>)}</ul>;
}

// FIX — wrap the update in startTransition or useTransition
'use client';
import { useState, useTransition } from 'react';

export function Search() {
  const [query, setQuery] = useState('');
  const [deferredQuery, setDeferredQuery] = useState('');
  const [isPending, startTransition] = useTransition();

  function handleChange(e: React.ChangeEvent<HTMLInputElement>) {
    setQuery(e.target.value);
    startTransition(() => {
      setDeferredQuery(e.target.value);
    });
  }

  return (
    <div>
      <input value={query} onChange={handleChange} />
      {isPending ? <p>Searching...</p> : <Results query={deferredQuery} />}
    </div>
  );
}
```

Use `useTransition` or `useDeferredValue` to mark non-urgent updates that may suspend. This keeps the input responsive while the results load.

This cryptic error often occurs when multiple React versions are installed, or when a dependency bundles its own React copy.

```
TypeError: Cannot read properties of null (reading 'useContext')
// or: Invalid hook call. Hooks can only be called inside of the body of a function component.
```

```bash
# Check for duplicate React installations
npm ls react
# Should show only one version (19.x)

# If you see duplicates, add resolutions:
# package.json
{
  "overrides": {
    "react": "$react",
    "react-dom": "$react-dom"
  }
}
```

```tsx
// Also check that react and react-dom versions match:
// package.json
{
  "dependencies": {
    "react": "^19.0.0",
    "react-dom": "^19.0.0"
  }
}
```

Run `npm dedupe` after fixing versions. This error is especially common after upgrading to React 19 when some packages still depend on React 18.

`generateMetadata` is a server-only function and cannot use hooks, browser APIs, or any client-side features.

```
Error: Expected a return value from generateMetadata.
// or: useState is not a function
```

```tsx
// BAD — using hooks in generateMetadata
import { useState } from 'react';

export async function generateMetadata() {
  const [title] = useState('Hello'); // Error!
  return { title };
}

// GOOD — server-only data fetching
import type { Metadata } from 'next';

export async function generateMetadata({
  params,
}: {
  params: Promise<{ slug: string }>;
}): Promise<Metadata> {
  const { slug } = await params;
  const post = await db.query.posts.findFirst({
    where: eq(posts.slug, slug),
  });

  return {
    title: post?.title ?? 'Not Found',
    description: post?.excerpt,
    openGraph: {
      title: post?.title,
      images: [{ url: post?.image ?? '/og-default.png' }],
    },
  };
}
```

`generateMetadata` runs on the server during rendering. It can use `fetch`, database queries, and other server-only operations, but not React hooks or browser APIs.

This error occurs when you import `useRouter` from `next/router` (Pages Router) instead of `next/navigation` (App Router).

```
Error: NextRouter was not mounted. See https://nextjs.org/docs/messages/next-router-not-mounted
```

```tsx
// BAD — Pages Router import
import { useRouter } from 'next/router';

// GOOD — App Router import
import { useRouter } from 'next/navigation';

// The APIs are different:
// next/router (Pages Router):
//   router.query — access query params
//   router.pathname — current path
//   router.asPath — full path

// next/navigation (App Router):
//   useRouter() — push, replace, back, forward, refresh, prefetch
//   usePathname() — current path
//   useSearchParams() — query params
//   useParams() — dynamic route params

'use client';
import { useRouter, usePathname, useSearchParams } from 'next/navigation';

export function Navigation() {
  const router = useRouter();
  const pathname = usePathname();
  const searchParams = useSearchParams();
  return <div>{pathname}?{searchParams.toString()}</div>;
}
```

Node.js built-in modules like `fs`, `path`, `net`, `child_process` are not available in the Edge Runtime used by middleware and edge route handlers.

```
Module not found: Can't resolve 'fs'
// or: The edge runtime does not support Node.js 'fs' module
```

```tsx
// BAD — using fs in middleware
import fs from 'fs';

export function middleware() {
  const config = fs.readFileSync('./config.json'); // Error!
}

// FIX — for middleware, use alternatives:
// 1. Fetch from an API route
export async function middleware(request: NextRequest) {
  const config = await fetch(new URL('/api/config', request.url));
  // ...
}

// 2. For Route Handlers, opt out of Edge Runtime:
// app/api/data/route.ts
export const runtime = 'nodejs'; // Use Node.js runtime instead of Edge

import fs from 'fs';
export async function GET() {
  const data = fs.readFileSync('./data.json', 'utf-8');
  return Response.json(JSON.parse(data));
}
```

Middleware always runs on the Edge Runtime and cannot be changed. Route Handlers and Server Components default to Node.js runtime but can opt into Edge with `export const runtime = 'edge'`.

This warning in the Next.js dev console indicates a page lost SSR benefits because a Client Component reads dynamic data without a Suspense boundary.

```
⚠ Entire page "/search" deopted into client-side rendering.
https://nextjs.org/docs/messages/deopted-into-client-rendering
```

```tsx
// Common cause: useSearchParams without Suspense
// BAD
'use client';
import { useSearchParams } from 'next/navigation';

export default function SearchPage() {
  const searchParams = useSearchParams(); // Deopts entire page!
  return <div>Query: {searchParams.get('q')}</div>;
}

// FIX — add Suspense boundary
import { Suspense } from 'react';

export default function SearchPage() {
  return (
    <Suspense fallback={<div>Loading search...</div>}>
      <SearchContent />
    </Suspense>
  );
}

function SearchContent() {
  'use client';
  const searchParams = useSearchParams();
  return <div>Query: {searchParams.get('q')}</div>;
}
```

This also happens with `useParams()` in some cases. Wrap Client Components that read URL state in `<Suspense>` boundaries.

When a Server Component needs multiple independent data sources, use `Promise.all` to fetch in parallel instead of sequential awaits.

```tsx
// BAD — sequential fetching (slow)
export default async function Dashboard() {
  const user = await getUser();         // 200ms
  const stats = await getStats();       // 300ms
  const notifications = await getNotifications(); // 150ms
  // Total: ~650ms

  return (
    <div>
      <UserProfile user={user} />
      <StatsPanel stats={stats} />
      <NotificationList notifications={notifications} />
    </div>
  );
}

// GOOD — parallel fetching
export default async function Dashboard() {
  const [user, stats, notifications] = await Promise.all([
    getUser(),
    getStats(),
    getNotifications(),
  ]);
  // Total: ~300ms (slowest request)

  return (
    <div>
      <UserProfile user={user} />
      <StatsPanel stats={stats} />
      <NotificationList notifications={notifications} />
    </div>
  );
}
```

For even better UX, combine parallel fetching with `<Suspense>` boundaries so each section streams independently as its data resolves.

Use multiple `<Suspense>` boundaries to stream different parts of a page independently. Fast data appears immediately while slow data streams in.

```tsx
import { Suspense } from 'react';

export default function DashboardPage() {
  return (
    <div className="grid grid-cols-2 gap-4">
      {/* Fast — renders immediately */}
      <Suspense fallback={<Skeleton className="h-32" />}>
        <QuickStats />
      </Suspense>

      {/* Slow — streams in later */}
      <Suspense fallback={<Skeleton className="h-64" />}>
        <RevenueChart />
      </Suspense>

      {/* Medium — streams independently */}
      <Suspense fallback={<Skeleton className="h-48" />}>
        <RecentOrders />
      </Suspense>
    </div>
  );
}

async function QuickStats() {
  const stats = await getQuickStats(); // 50ms
  return <div>{stats.totalRevenue}</div>;
}

async function RevenueChart() {
  const data = await getRevenueData(); // 2000ms
  return <Chart data={data} />;
}

async function RecentOrders() {
  const orders = await getRecentOrders(); // 500ms
  return <OrderTable orders={orders} />;
}
```

Each `<Suspense>` boundary creates a separate streaming chunk. The page shell and fast sections render first, then slower sections fill in as they resolve.

The recommended pattern for form handling in Next.js 15 combines Server Actions with `useActionState` for progressive enhancement.

```tsx
// app/actions.ts
'use server';
import { z } from 'zod';
import { revalidatePath } from 'next/cache';

const schema = z.object({
  title: z.string().min(1, 'Title is required').max(100),
  content: z.string().min(10, 'Content must be at least 10 characters'),
});

export type FormState = {
  errors?: { title?: string[]; content?: string[] };
  message?: string;
};

export async function createPost(
  prevState: FormState,
  formData: FormData
): Promise<FormState> {
  const parsed = schema.safeParse(Object.fromEntries(formData));
  if (!parsed.success) {
    return { errors: parsed.error.flatten().fieldErrors };
  }
  await db.insert(posts).values(parsed.data);
  revalidatePath('/posts');
  return { message: 'Post created!' };
}

// components/post-form.tsx
'use client';
import { useActionState } from 'react';
import { createPost, type FormState } from '@/app/actions';

export function PostForm() {
  const [state, formAction, isPending] = useActionState(createPost, {});
  return (
    <form action={formAction}>
      <input name="title" />
      {state.errors?.title && <p className="text-red-500">{state.errors.title[0]}</p>}
      <textarea name="content" />
      {state.errors?.content && <p className="text-red-500">{state.errors.content[0]}</p>}
      <button disabled={isPending}>{isPending ? 'Creating...' : 'Create'}</button>
      {state.message && <p className="text-green-500">{state.message}</p>}
    </form>
  );
}
```

This pattern works without JavaScript (progressive enhancement), shows validation errors, handles loading states, and revalidates cached data after mutation.

For auth checks, use middleware for route protection and layouts for passing user data down. Never fetch auth state in every component.

```tsx
// middleware.ts — route protection
import { NextResponse } from 'next/server';
import type { NextRequest } from 'next/server';

export function middleware(request: NextRequest) {
  const token = request.cookies.get('session')?.value;
  if (!token && request.nextUrl.pathname.startsWith('/dashboard')) {
    return NextResponse.redirect(new URL('/login', request.url));
  }
  return NextResponse.next();
}

export const config = {
  matcher: ['/dashboard/:path*', '/settings/:path*'],
};

// app/dashboard/layout.tsx — pass user data to children
import { cookies } from 'next/headers';
import { verifyToken } from '@/lib/auth';
import { redirect } from 'next/navigation';

export default async function DashboardLayout({
  children,
}: {
  children: React.ReactNode;
}) {
  const cookieStore = await cookies();
  const token = cookieStore.get('session')?.value;
  const user = token ? await verifyToken(token) : null;

  if (!user) redirect('/login');

  return (
    <div>
      <nav>Welcome, {user.name}</nav>
      {children}
    </div>
  );
}
```

Middleware runs on every request at the edge (fast, lightweight checks). Layouts run on the server with full Node.js access (database queries, JWT verification). Use both together for defense in depth.

Use `useOptimistic` for instant UI feedback while a Server Action processes in the background.

```tsx
// app/actions.ts
'use server';
import { revalidatePath } from 'next/cache';

export async function toggleTodo(id: string, completed: boolean) {
  await db.update(todos).set({ completed }).where(eq(todos.id, id));
  revalidatePath('/todos');
}

// components/todo-list.tsx
'use client';
import { useOptimistic, startTransition } from 'react';
import { toggleTodo } from '@/app/actions';

type Todo = { id: string; title: string; completed: boolean };

export function TodoList({ todos }: { todos: Todo[] }) {
  const [optimisticTodos, setOptimisticTodos] = useOptimistic(
    todos,
    (state, { id, completed }: { id: string; completed: boolean }) =>
      state.map((t) => (t.id === id ? { ...t, completed } : t))
  );

  function handleToggle(id: string, completed: boolean) {
    startTransition(async () => {
      setOptimisticTodos({ id, completed: !completed });
      await toggleTodo(id, !completed);
    });
  }

  return (
    <ul>
      {optimisticTodos.map((todo) => (
        <li key={todo.id}>
          <input
            type="checkbox"
            checked={todo.completed}
            onChange={() => handleToggle(todo.id, todo.completed)}
          />
          {todo.title}
        </li>
      ))}
    </ul>
  );
}
```

The checkbox toggles instantly via optimistic state. When the Server Action completes and `revalidatePath` triggers, the optimistic state is replaced with the real server data.

Pass a Promise from a Server Component to a Client Component and read it with `use()`. This enables streaming without waterfall fetching.

```tsx
// app/page.tsx (Server Component)
import { UserProfile } from './user-profile';

export default function Page() {
  // Start fetching immediately — don't await here!
  const userPromise = getUser();
  const postsPromise = getPosts();

  return (
    <div>
      <Suspense fallback={<p>Loading user...</p>}>
        <UserProfile userPromise={userPromise} postsPromise={postsPromise} />
      </Suspense>
    </div>
  );
}

// user-profile.tsx
'use client';
import { use } from 'react';

export function UserProfile({
  userPromise,
  postsPromise,
}: {
  userPromise: Promise<User>;
  postsPromise: Promise<Post[]>;
}) {
  const user = use(userPromise);
  const posts = use(postsPromise);

  return (
    <div>
      <h1>{user.name}</h1>
      <ul>
        {posts.map((p) => <li key={p.id}>{p.title}</li>)}
      </ul>
    </div>
  );
}
```

By not awaiting in the Server Component, both promises start fetching immediately and the Client Component suspends until both resolve. The `<Suspense>` boundary shows the fallback while suspended.

A clean pattern for Route Handlers in Next.js 15 with proper typing, validation, and error handling.

```tsx
// app/api/posts/route.ts
import { NextRequest } from 'next/server';
import { z } from 'zod';

const createPostSchema = z.object({
  title: z.string().min(1).max(200),
  content: z.string().min(1),
  published: z.boolean().default(false),
});

export async function GET(request: NextRequest) {
  const searchParams = request.nextUrl.searchParams;
  const page = parseInt(searchParams.get('page') ?? '1');
  const limit = parseInt(searchParams.get('limit') ?? '10');

  const posts = await db.query.posts.findMany({
    limit,
    offset: (page - 1) * limit,
    orderBy: (posts, { desc }) => [desc(posts.createdAt)],
  });

  return Response.json({ data: posts, page, limit });
}

export async function POST(request: NextRequest) {
  try {
    const body = await request.json();
    const parsed = createPostSchema.safeParse(body);

    if (!parsed.success) {
      return Response.json(
        { error: 'Validation failed', details: parsed.error.flatten() },
        { status: 400 }
      );
    }

    const post = await db.insert(posts).values(parsed.data).returning();
    return Response.json({ data: post[0] }, { status: 201 });
  } catch (error) {
    return Response.json(
      { error: 'Internal server error' },
      { status: 500 }
    );
  }
}
```

Route Handlers support `GET`, `POST`, `PUT`, `PATCH`, `DELETE`, `HEAD`, and `OPTIONS`. Use them for public APIs; use Server Actions for mutations tied to UI forms.

Server Actions and Route Handlers serve different purposes. Use Server Actions for form mutations and Route Handlers for API endpoints.

```tsx
// USE SERVER ACTIONS when:
// - Handling form submissions
// - Mutating data from UI interactions
// - Need revalidation after mutation
// - Want progressive enhancement (works without JS)

'use server';
export async function updateProfile(formData: FormData) {
  const name = formData.get('name') as string;
  await db.update(users).set({ name }).where(eq(users.id, currentUser.id));
  revalidatePath('/profile');
}

// USE ROUTE HANDLERS when:
// - Building a public API consumed by external clients
// - Handling webhooks
// - File uploads with progress
// - Streaming responses
// - Need specific HTTP method handling

// app/api/webhook/route.ts
export async function POST(request: Request) {
  const signature = request.headers.get('x-webhook-signature');
  if (!verifySignature(signature, await request.text())) {
    return Response.json({ error: 'Invalid signature' }, { status: 401 });
  }
  // Process webhook...
  return Response.json({ received: true });
}
```

Server Actions are RPC-style (function call), Route Handlers are REST-style (HTTP methods). Server Actions automatically handle CSRF protection; Route Handlers need manual CORS/auth handling.

Use `React.cache()` to deduplicate data fetching across layouts and pages in the same request without prop drilling.

```tsx
// lib/get-user.ts
import { cache } from 'react';
import { cookies } from 'next/headers';

export const getUser = cache(async () => {
  const cookieStore = await cookies();
  const token = cookieStore.get('session')?.value;
  if (!token) return null;
  return verifyAndGetUser(token);
});

// app/dashboard/layout.tsx
import { getUser } from '@/lib/get-user';

export default async function DashboardLayout({ children }: { children: React.ReactNode }) {
  const user = await getUser(); // First call — fetches
  if (!user) redirect('/login');
  return (
    <div>
      <nav>Welcome, {user.name}</nav>
      {children}
    </div>
  );
}

// app/dashboard/page.tsx
import { getUser } from '@/lib/get-user';

export default async function DashboardPage() {
  const user = await getUser(); // Deduplicated — returns cached result
  return <h1>{user.name}'s Dashboard</h1>;
}
```

`React.cache()` deduplicates within a single server request. It does not persist across requests — that is what `fetch` caching or `unstable_cache` does. Both the layout and page call `getUser()` but only one actual execution happens.

A reusable pattern for creating type-safe Server Actions with consistent error handling using Zod.

```tsx
// lib/action-utils.ts
import { z } from 'zod';

export type ActionResult<T = void> =
  | { success: true; data: T }
  | { success: false; error: string; fieldErrors?: Record<string, string[]> };

export function createAction<TInput, TOutput>(
  schema: z.ZodSchema<TInput>,
  handler: (data: TInput) => Promise<TOutput>
) {
  return async (
    _prevState: ActionResult<TOutput>,
    formData: FormData
  ): Promise<ActionResult<TOutput>> => {
    const parsed = schema.safeParse(Object.fromEntries(formData));
    if (!parsed.success) {
      return {
        success: false,
        error: 'Validation failed',
        fieldErrors: parsed.error.flatten().fieldErrors as Record<string, string[]>,
      };
    }
    try {
      const result = await handler(parsed.data);
      return { success: true, data: result };
    } catch (e) {
      return { success: false, error: e instanceof Error ? e.message : 'Unknown error' };
    }
  };
}

// app/actions.ts
'use server';
import { createAction } from '@/lib/action-utils';

export const createPost = createAction(
  z.object({ title: z.string().min(1), content: z.string().min(10) }),
  async (data) => {
    const post = await db.insert(posts).values(data).returning();
    revalidatePath('/posts');
    return post[0];
  }
);
```

This pattern separates validation, error handling, and business logic. The `ActionResult` type makes it easy to handle success/error states in Client Components.

Use parallel routes and intercepting routes to build modals that have their own URL, support back/forward navigation, and are shareable.

```
app/
  layout.tsx
  page.tsx
  @modal/
    default.tsx
    (.)posts/
      [id]/
        page.tsx
  posts/
    [id]/
      page.tsx
```

```tsx
// app/layout.tsx
export default function Layout({
  children,
  modal,
}: {
  children: React.ReactNode;
  modal: React.ReactNode;
}) {
  return (
    <html><body>
      {children}
      {modal}
    </body></html>
  );
}

// app/@modal/default.tsx
export default function Default() {
  return null;
}

// app/@modal/(.)posts/[id]/page.tsx — intercepted (modal view)
export default async function PostModal({ params }: { params: Promise<{ id: string }> }) {
  const { id } = await params;
  const post = await getPost(id);
  return (
    <Dialog>
      <h2>{post.title}</h2>
      <p>{post.content}</p>
    </Dialog>
  );
}

// app/posts/[id]/page.tsx — full page (direct navigation or hard refresh)
export default async function PostPage({ params }: { params: Promise<{ id: string }> }) {
  const { id } = await params;
  const post = await getPost(id);
  return <article><h1>{post.title}</h1><p>{post.content}</p></article>;
}
```

Soft navigation from the list shows the modal. Direct URL access or hard refresh shows the full page. This is the Instagram/Twitter photo modal pattern.

Configure middleware matchers to run only on specific routes, improving performance by skipping static assets and API routes.

```tsx
// middleware.ts
import { NextResponse } from 'next/server';
import type { NextRequest } from 'next/server';

export function middleware(request: NextRequest) {
  const token = request.cookies.get('session')?.value;

  // Check auth for protected routes
  if (!token) {
    const loginUrl = new URL('/login', request.url);
    loginUrl.searchParams.set('from', request.nextUrl.pathname);
    return NextResponse.redirect(loginUrl);
  }

  // Add custom headers
  const response = NextResponse.next();
  response.headers.set('x-user-authenticated', 'true');
  return response;
}

// Only run on these paths — skip static files, images, etc.
export const config = {
  matcher: [
    // Match all paths except static files and _next
    '/((?!_next/static|_next/image|favicon.ico|public/).*)',
    // Or be explicit:
    '/dashboard/:path*',
    '/settings/:path*',
    '/api/protected/:path*',
  ],
};
```

The matcher uses a subset of regex. `:path*` matches zero or more path segments. Always exclude `_next/static`, `_next/image`, and `favicon.ico` to avoid running middleware on static assets.

Keep search state in the URL for shareability and SSR, using `useSearchParams` in a Client Component and reading `searchParams` in Server Components.

```tsx
// components/search-input.tsx
'use client';
import { useSearchParams, useRouter, usePathname } from 'next/navigation';
import { useDebouncedCallback } from 'use-debounce';

export function SearchInput() {
  const searchParams = useSearchParams();
  const pathname = usePathname();
  const router = useRouter();

  const handleSearch = useDebouncedCallback((term: string) => {
    const params = new URLSearchParams(searchParams.toString());
    if (term) {
      params.set('q', term);
    } else {
      params.delete('q');
    }
    params.set('page', '1');
    router.replace(`${pathname}?${params.toString()}`);
  }, 300);

  return (
    <input
      defaultValue={searchParams.get('q') ?? ''}
      onChange={(e) => handleSearch(e.target.value)}
      placeholder="Search..."
    />
  );
}

// app/posts/page.tsx (Server Component)
export default async function PostsPage({
  searchParams,
}: {
  searchParams: Promise<{ q?: string; page?: string }>;
}) {
  const { q, page } = await searchParams;
  const posts = await searchPosts(q, parseInt(page ?? '1'));
  return (
    <div>
      <SearchInput />
      <PostList posts={posts} />
    </div>
  );
}
```

The URL is the single source of truth. The Server Component reads `searchParams` and fetches data. The Client Component updates the URL on input change.

