Trigger ISR revalidation from a CMS webhook using a Route Handler with a secret token.

```tsx
// app/api/revalidate/route.ts
import { revalidatePath, revalidateTag } from 'next/cache';
import { NextRequest } from 'next/server';

export async function POST(request: NextRequest) {
  const body = await request.json();
  const secret = request.headers.get('x-revalidation-secret');

  if (secret !== process.env.REVALIDATION_SECRET) {
    return Response.json({ error: 'Invalid secret' }, { status: 401 });
  }

  // Revalidate specific paths or tags based on webhook payload
  switch (body.type) {
    case 'post.published':
    case 'post.updated':
      revalidateTag('posts');
      revalidatePath(`/posts/${body.slug}`);
      break;
    case 'page.updated':
      revalidatePath(body.path);
      break;
    default:
      revalidatePath('/', 'layout'); // Revalidate everything
  }

  return Response.json({ revalidated: true, now: Date.now() });
}

// In your data fetching, tag requests for granular revalidation:
async function getPosts() {
  const res = await fetch('https://cms.example.com/api/posts', {
    next: { tags: ['posts'] },
  });
  return res.json();
}
```

This pattern lets your CMS trigger revalidation only for changed content. Use `revalidateTag` for granular control and `revalidatePath` for specific pages.

