```tsx
// app/actions.ts
'use server';
export async function loadMorePosts(offset: number, limit: number = 10) {
  const posts = await db.query.posts.findMany({
    offset,
    limit,
    orderBy: (posts, { desc }) => [desc(posts.createdAt)],
  });
