// components/infinite-posts.tsx
'use client';
import { useState, useTransition, useCallback, useEffect, useRef } from 'react';
import { loadMorePosts } from '@/app/actions';

export function InfinitePosts({ initialPosts }: { initialPosts: Post[] }) {
  const [posts, setPosts] = useState(initialPosts);
  const [isPending, startTransition] = useTransition();
  const [hasMore, setHasMore] = useState(true);
  const loaderRef = useRef<HTMLDivElement>(null);

  const loadMore = useCallback(() => {
    if (isPending || !hasMore) return;
    startTransition(async () => {
      const newPosts = await loadMorePosts(posts.length);
      if (newPosts.length === 0) setHasMore(false);
      else setPosts((prev) => [...prev, ...newPosts]);
    });
  }, [posts.length, isPending, hasMore]);

  useEffect(() => {
    const observer = new IntersectionObserver(
      ([entry]) => { if (entry.isIntersecting) loadMore(); },
      { threshold: 0.1 }
    );
    if (loaderRef.current) observer.observe(loaderRef.current);
    return () => observer.disconnect();
  }, [loadMore]);

  return (
    <div>
      {posts.map((p) => <PostCard key={p.id} post={p} />)}
      <div ref={loaderRef}>
        {isPending && <p>Loading more...</p>}
      </div>
    </div>
  );
}
