Handle file uploads in a Server Action with validation.

```tsx
// app/actions.ts
'use server';
import { writeFile } from 'fs/promises';
import path from 'path';

export async function uploadFile(
  prevState: { message: string; url?: string },
  formData: FormData
) {
  const file = formData.get('file') as File;

  if (!file || file.size === 0) {
    return { message: 'No file selected' };
  }

  if (file.size > 5 * 1024 * 1024) {
    return { message: 'File must be less than 5MB' };
  }

  const allowedTypes = ['image/jpeg', 'image/png', 'image/webp'];
  if (!allowedTypes.includes(file.type)) {
    return { message: 'Only JPEG, PNG, and WebP images are allowed' };
  }

  const bytes = await file.arrayBuffer();
  const buffer = Buffer.from(bytes);
  const filename = `${Date.now()}-${file.name}`;
  const filepath = path.join(process.cwd(), 'public/uploads', filename);
  await writeFile(filepath, buffer);

  return { message: 'Upload successful', url: `/uploads/${filename}` };
}

