  const docs = await getAllDocs();
  return docs.map((doc) => ({
    slug: doc.path.split('/'), // Must be an array
  }));
}

// app/shop/[[...slug]]/page.tsx — optional catch-all
// Matches: /shop, /shop/shirts, /shop/shirts/xl
export default async function ShopPage({
  params,
}: {
  params: Promise<{ slug?: string[] }>;
}) {
  const { slug } = await params;
  // slug = undefined for /shop
  // slug = ['shirts'] for /shop/shirts
  // slug = ['shirts', 'xl'] for /shop/shirts/xl

  if (!slug) return <AllProducts />;
  return <FilteredProducts categories={slug} />;
}
